import React, { useState, useRef } from 'react';

export default function VerificationInput({ onComplete }) {
  const [code, setCode] = useState(Array(6).fill(""));
  const inputRefs = useRef([]);

  const handleChange = (e, index) => {
    const value = e.target.value;
    if (isNaN(value)) return;

    const newCode = [...code];
    // Take only the last entered char (handles override)
    newCode[index] = value.substring(value.length - 1);
    setCode(newCode);

    // Send complete code callback
    const joined = newCode.join("");
    if (joined.length === 6 && onComplete) {
      onComplete(joined);
    }

    // Auto-focus next box
    if (value && index < 5) {
      inputRefs.current[index + 1].focus();
    }
  };

  const handleKeyDown = (e, index) => {
    if (e.key === "Backspace") {
      if (!code[index] && index > 0) {
        // Shift focus back and clear previous box
        inputRefs.current[index - 1].focus();
        const newCode = [...code];
        newCode[index - 1] = "";
        setCode(newCode);
      } else {
        const newCode = [...code];
        newCode[index] = "";
        setCode(newCode);
      }
    }
  };

  const handlePaste = (e) => {
    e.preventDefault();
    const pasteData = e.clipboardData.getData("text").trim();
    if (pasteData.length !== 6 || isNaN(pasteData)) return;

    const newCode = pasteData.split("");
    setCode(newCode);
    inputRefs.current[5].focus();

    if (onComplete) {
      onComplete(pasteData);
    }
  };

  return (
    <div className="flex gap-3 justify-center items-center">
      {code.map((digit, idx) => (
        <input
          key={idx}
          type="text"
          maxLength={1}
          value={digit}
          ref={el => (inputRefs.current[idx] = el)}
          onChange={(e) => handleChange(e, idx)}
          onKeyDown={(e) => handleKeyDown(e, idx)}
          onPaste={handlePaste}
          className="w-12 h-14 border-2 border-gray-300 rounded-lg text-center font-bold text-xl text-gray-800 focus:border-purple-500 focus:outline-none focus:ring-2 focus:ring-purple-200 transition"
        />
      ))}
    </div>
  );
}
